import asyncio
import grpc
from grpc import aio
from concurrent import futures
import logging
from typing import AsyncIterator
import json
import os
from cryptography.fernet import Fernet
import hashlib

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Security configuration
class SecurityManager:
    def __init__(self):
        self.key = os.environ.get('GRPC_SECRET_KEY', Fernet.generate_key())
        self.cipher = Fernet(self.key)
    
    def encrypt_data(self, data: str) -> bytes:
        return self.cipher.encrypt(data.encode())
    
    def decrypt_data(self, encrypted_data: bytes) -> str:
        return self.cipher.decrypt(encrypted_data).decode()

# Initialize security manager
security_manager = SecurityManager()

# gRPC service implementation
class DataStreamService:
    def __init__(self):
        self.processed_count = 0
        self.active_connections = 0
    
    async def process_stream(self, request_iterator, context):
        """Process incoming data stream with high throughput"""
        try:
            async for request in request_iterator:
                # Process each message in the stream
                processed_data = await self._process_message(request)
                yield processed_data
                self.processed_count += 1
                
        except Exception as e:
            logger.error(f"Stream processing error: {e}")
            await context.abort(grpc.StatusCode.INTERNAL, "Internal processing error")
    
    async def _process_message(self, message):
        """Process individual message with minimal overhead"""
        # Simulate processing
        processed_message = {
            'id': message.id,
            'timestamp': message.timestamp,
            'data': security_manager.encrypt_data(message.data).decode(),
            'processed_count': self.processed_count
        }
        return processed_message

# Define the gRPC service
class DataStreamServicer(DataStreamService, grpc.StreamStreamServicer):
    async def ProcessStream(self, request_iterator, context):
        return await self.process_stream(request_iterator, context)

# gRPC server configuration
def create_grpc_server():
    """Create and configure gRPC server with high performance settings"""
    server = aio.server(
        futures.ThreadPoolExecutor(max_workers=100),
        options=[
            ('grpc.max_send_message_length', -1),
            ('grpc.max_receive_message_length', -1),
            ('grpc.so_reuseport', 1),
            ('grpc.max_concurrent_streams', 1000),
            ('grpc.keepalive_time_ms', 60000),
            ('grpc.keepalive_timeout_ms', 5000),
        ]
    )
    
    # Add service to server
    grpc.add_to_server(DataStreamServicer(), server)
    
    # Configure secure channel
    server_credentials = grpc.ssl_server_credentials(
        private_key_certificate_chain_pairs=[
            (
                open('server.key', 'rb').read(),
                open('server.crt', 'rb').read()
            )
        ]
    )
    
    server.add_secure_port('[::]:50051', server_credentials)
    return server

# Main server startup
async def main():
    """Main server startup function"""
    try:
        server = create_grpc_server()
        await server.start()
        logger.info("gRPC Server started on port 50051")
        
        # Keep server running
        await server.wait_for_termination()
        
    except Exception as e:
        logger.error(f"Server error: {e}")
        raise

if __name__ == '__main__':
    asyncio.run(main())